#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(b,c) for(int c=head[(b)];c;c=nxt[c])
//#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline int Min(int x,int y){return x<y?x:y;}
inline int Max(int x,int y){return x>y?x:y;}
const int N=4e5+10;
int ch[N][26],len[N],fa[N],lst=1,tot=1;char s[N];
inline void ins(short c)
{
	int p=lst,np=lst=++tot;len[np]=len[p]+1;
	for(;p&&!ch[p][c];p=fa[p])ch[p][c]=np;
	if(!p){fa[np]=1;}
	else
	{
		int v=ch[p][c];if(len[v]==len[p]+1)fa[np]=v;
		else
		{
			int nv=++tot;len[nv]=len[p]+1;fa[nv]=fa[v];
			memcpy(ch[nv],ch[v],sizeof(ch[v]));
			for(;p&&ch[p][c]==v;p=fa[p])ch[p][c]=nv;
			fa[v]=fa[np]=nv;
		}
	}
}
int head[N],des[N],nxt[N],cgt,mn[N],mx[N];
inline void ins(int x,int y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;}
inline void dfs(int u){grep(u,i)dfs(des[i]),mx[u]=Max(mx[u],Min(mx[des[i]],len[u]));}
inline void Solve()
{
	memset(head+1,0,tot<<2);memset(fa+1,0,tot<<2);
	rep(1,tot,i)memset(ch[i],0,sizeof(ch[i]));memset(len+1,0,tot<<2);
	lst=tot=1;cgt=0;memset(mn,0x3f,sizeof(mn));int tt=read();
	scanf("%s",s+1);int n=strlen(s+1);rep(1,n,i)ins(s[i]-'a');
	rep(2,tot,i)ins(fa[i],i);rep(2,tt,i)
	{
		scanf("%s",s+1);int n=strlen(s+1),p=1,mxl=0;
		rep(1,n,i)
		{
			short c=s[i]-'a';while(p&&!ch[p][c])mxl=len[p=fa[p]];
			if(ch[p][c])p=ch[p][c],++mxl;else p=1,mxl=0;mx[p]=Max(mx[p],mxl);
		}
		dfs(1);rep(1,tot,i)mn[i]=Min(mn[i],mx[i]),mx[i]=0;
	}
	int ans=0;rep(1,tot,i)ans=Max(mn[i],ans);printf("%d\n",ans);return;
	
}
int main(){int T=read();while(T--)Solve();return 0;}
